mapper.select:
SELECT * FROM diary
WHERE user_id = #{userId}
AND deleted_at IS NULL
AND locked = 0
AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d')

    AND mood_key = #{moodKey}


    AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

ORDER BY date DESC, created_at DESC
LIMIT #{limit} OFFSET #{offset}

SELECT diary_id, user_id, title, date, LEFT(content, 512) AS content, mood_key, content_format, created_at FROM diary WHERE user_id = #{userId} AND deleted_at IS NULL AND locked = 0 AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d')
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})
ORDER BY date DESC, created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM diary WHERE user_id = #{userId} AND deleted_at IS NULL AND locked = 0 AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d')
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

SELECT * FROM diary
WHERE user_id = #{userId}
  AND deleted_at IS NULL
  AND locked = 0
  AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d') and
  (title LIKE CONCAT('%', #{searchKeyword}, '%') OR content LIKE CONCAT('%', #{searchKeyword}, '%'))

    AND mood_key = #{moodKey}


    AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

ORDER BY date DESC, created_at DESC
    LIMIT #{limit} OFFSET #{offset}

SELECT diary_id, user_id, title, date, LEFT(content, 512) AS content, mood_key, content_format, created_at FROM diary WHERE user_id = #{userId} AND deleted_at IS NULL AND locked = 0 AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d') and (title LIKE CONCAT('%', #{searchKeyword}, '%') OR content LIKE CONCAT('%', #{searchKeyword}, '%'))
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})
ORDER BY date DESC, created_at DESC LIMIT #{limit} OFFSET #{offset}

SELECT COUNT(*) FROM diary WHERE user_id = #{userId} AND deleted_at IS NULL AND locked = 0 AND date BETWEEN STR_TO_DATE(#{startDate},'%Y-%m-%d') AND STR_TO_DATE(#{endDate},'%Y-%m-%d') and (title LIKE CONCAT('%', #{searchKeyword}, '%') OR content LIKE CONCAT('%', #{searchKeyword}, '%'))
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})

SELECT diary_id, user_id, title, date, LEFT(content, 512) AS content, mood_key, content_format, created_at FROM diary WHERE user_id = #{userId} AND deleted_at IS NULL AND locked = 0
AND date >= #{startDate}
AND date <= #{endDate}
AND mood_key = #{moodKey}
AND EXISTS (SELECT 1 FROM diary_tag dt WHERE dt.diary_id = diary.diary_id AND dt.tag_id = #{tagId})
ORDER BY date DESC, created_at DESC

SELECT * FROM diary
WHERE user_id = #{userId}
  AND deleted_at IS NULL
  AND locked = 0
  AND date BETWEEN #{startDate} AND #{endDate}
ORDER BY date ASC, created_at ASC
